using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Tool implementations ---

var notebook = new ResearchNotebook();

[Description("Search the web for information on a query. Returns a list of result snippets.")]
string WebSearch([Description("The search query")] string query)
{
    // Brave Search API (free tier) – falls back to a simulated result when no key is set.
    var apiKey = Environment.GetEnvironmentVariable("BRAVE_API_KEY");
    if (!string.IsNullOrEmpty(apiKey))
    {
        using var http = new HttpClient();
        http.DefaultRequestHeaders.Add("Accept", "application/json");
        http.DefaultRequestHeaders.Add("X-Subscription-Token", apiKey);
        var url = $"https://api.search.brave.com/res/v1/web/search?q={Uri.EscapeDataString(query)}&count=5";
        var resp = http.GetFromJsonAsync<JsonElement>(url).GetAwaiter().GetResult();
        var results = new List<string>();
        if (resp.TryGetProperty("web", out var web) && web.TryGetProperty("results", out var items))
        {
            foreach (var item in items.EnumerateArray().Take(5))
            {
                var title = item.GetProperty("title").GetString();
                var snippet = item.GetProperty("description").GetString();
                var link = item.GetProperty("url").GetString();
                results.Add($"[{title}]({link}): {snippet}");
            }
        }
        if (results.Count > 0)
            return string.Join("\n\n", results);
    }

    // Simulated fallback so the app works without an API key
    return $"""
        Search results for "{query}":
        1. [Overview of {query} - Wikipedia](https://en.wikipedia.org/wiki/{Uri.EscapeDataString(query)}): {query} is a broad topic with many facets spanning history, current developments, and future outlook.
        2. [Recent advances in {query} - Nature](https://nature.com/articles/{query.Replace(' ', '-')}): Researchers have made significant progress in {query}, with breakthroughs reported in 2025-2026.
        3. [{query}: A Comprehensive Guide - TechReview](https://techreview.com/{query.Replace(' ', '-')}): This guide covers the fundamentals, key players, and emerging trends in {query}.
        4. [The Future of {query} - MIT Tech Review](https://technologyreview.com/{query.Replace(' ', '-')}): Experts predict major shifts in {query} over the next decade.
        5. [{query} Market Analysis 2026 - Reuters](https://reuters.com/{query.Replace(' ', '-')}): The global landscape for {query} is evolving rapidly with new entrants and technologies.
        """;
}

[Description("Save a research note with a title and body. Use this to record important findings.")]
string SaveNote(
    [Description("Short title for the note")] string title,
    [Description("Detailed content of the note")] string content)
{
    notebook.Add(title, content);
    return $"Note saved: \"{title}\" ({content.Length} chars). You now have {notebook.Count} note(s).";
}

[Description("Retrieve all saved research notes.")]
string GetNotes()
{
    return notebook.Count == 0
        ? "No notes saved yet."
        : notebook.ToString();
}

// --- Build the AI chat client with tools ---

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
var chatClient = new OpenAIClient(
        Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "test-key")
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var tools = new[]
{
    AIFunctionFactory.Create(WebSearch),
    AIFunctionFactory.Create(SaveNote),
    AIFunctionFactory.Create(GetNotes),
};

var chatOptions = new ChatOptions { Tools = [.. tools] };

// --- Agent loop ---

var topic = args.Length > 0 ? string.Join(' ', args) : "quantum computing";

Console.WriteLine($"🔍 Research Agent Starting — Topic: \"{topic}\"\n");

var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your goal is to thoroughly research the given topic using the
        available tools. Follow this process:
        1. Search the web for the topic from multiple angles (at least 2-3 searches with different queries).
        2. Save important findings as notes using the SaveNote tool.
        3. After gathering enough information, retrieve your notes and produce a final comprehensive
           summary with key findings, organized by subtopic.
        Be thorough but concise. Cite sources where possible.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a comprehensive summary: {topic}")
};

Console.WriteLine("Agent is researching... (this may take a moment)\n");

var response = await chatClient.GetResponseAsync(messages, chatOptions);

Console.WriteLine("═══════════════════════════════════════════");
Console.WriteLine("            RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════════\n");
Console.WriteLine(response.Text);
Console.WriteLine("\n═══════════════════════════════════════════");
Console.WriteLine($"  📝 {notebook.Count} note(s) collected during research");
Console.WriteLine("═══════════════════════════════════════════");

// --- Notebook helper ---

class ResearchNotebook
{
    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];

    public int Count => _notes.Count;

    public void Add(string title, string content) =>
        _notes.Add((title, content, DateTime.UtcNow));

    public override string ToString()
    {
        var sb = new System.Text.StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            var (title, content, ts) = _notes[i];
            sb.AppendLine($"--- Note {i + 1}: {title} (saved {ts:HH:mm:ss UTC}) ---");
            sb.AppendLine(content);
            sb.AppendLine();
        }
        return sb.ToString();
    }
}

